// app/page.tsx
import { createPost } from './actions';

interface Post {
  id: string;
  title: string;
  content: string;
  createdAt: string;
}

async function fetchPosts(): Promise<Post[]> {
  const protocol = process.env.NODE_ENV === 'development' ? 'http' : 'https';
  const host = process.env.VERCEL_URL || 'localhost:3000';
  const res = await fetch(`${protocol}://${host}/api/posts`, {
    next: { tags: ['posts'] },
  });
  if (!res.ok) {
    throw new Error('Failed to fetch posts');
  }
  return res.json();
}

export default async function Home() {
  const posts = await fetchPosts();

  return (
    <main>
      <h1>Posts</h1>

      <form action={createPost}>
        <div>
          <label htmlFor="title">Title</label>
          <input type="text" id="title" name="title" required />
        </div>
        <div>
          <label htmlFor="content">Content</label>
          <textarea id="content" name="content" required />
        </div>
        <button type="submit">Create Post</button>
      </form>

      <ul>
        {posts.map((post) => (
          <li key={post.id}>
            <h2>{post.title}</h2>
            <p>{post.content}</p>
            <small>{new Date(post.createdAt).toLocaleDateString()}</small>
          </li>
        ))}
      </ul>
    </main>
  );
}


// app/actions.ts
'use server';

import { revalidateTag } from 'next/cache';
import { addPost } from '@/lib/posts';

export async function createPost(formData: FormData) {
  const title = formData.get('title') as string;
  const content = formData.get('content') as string;

  if (!title || !content) {
    throw new Error('Title and content are required');
  }

  addPost(title, content);

  // Invalidate the "posts" cache tag so the next page load fetches
  // fresh data instead of serving stale cached content.
  // { expire: 0 } forces immediate expiration — no stale cache served.
  revalidateTag('posts', { expire: 0 });
}


// lib/posts.ts
export interface Post {
  id: string;
  title: string;
  content: string;
  createdAt: Date;
}

const posts: Post[] = [
  {
    id: '1',
    title: 'Welcome',
    content: 'This is the first post.',
    createdAt: new Date('2026-07-01'),
  },
];

export function getPosts(): Post[] {
  return posts;
}

export function addPost(title: string, content: string): Post {
  const newPost: Post = {
    id: String(Date.now()),
    title,
    content,
    createdAt: new Date(),
  };
  posts.push(newPost);
  return newPost;
}


// app/api/posts/route.ts
import { NextResponse } from 'next/server';
import { getPosts } from '@/lib/posts';

export async function GET() {
  const posts = getPosts();
  return NextResponse.json(posts);
}
